import React, { Fragment, useEffect, useRef, useState } from 'react';
import { useReactToPrint } from 'react-to-print';
import { getpaymentId, getpaymentIdMaster, getpaymentIdRole, getShareApi } from '../../../CommonUrl';
import { useSelector } from 'react-redux';
import { getClientUrlDataToken, getMasterDataToken } from '../../../Utils/restUtils';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import Transparentspinner from '../../Common/Loader/Transparentspinner';
import { Col, Media, Row } from 'reactstrap';
import { IssuedMay, PaymentDue, Email, Mob, TaxIn, Txn, SalesAgent } from '../../../Constant';
import { H3, H2, P, Image, H4 } from '../../../AbstractElements';
import logo from '../../../assets/images/logo/dark-logog.svg'
import logo2 from '../../../assets/images/logo/logo-icon-black.svg'

const RenewSub = () => {
    const [spinnerTrans, setspinnerTrans] = useState(true);
    const authState = useSelector((state) => state.auth);
    const location = useLocation();
    const searchParams = location.search;
    const params = new URLSearchParams(searchParams);
    const param1 = params.get("payment_id");
    const [apidata, setapidata] = useState('');
    const navigate = useNavigate();
    const [invoice, setinvoice] = useState(null);
    const imageUrl = apidata.company_logo_url
        ;

    useEffect(() => {
        handlePayment();
    }, []);
    const isAdmin = location?.pathname === '/billing/thermal-print-admin'

    const componentRef = useRef(null);
    const componentRefFullPage = useRef(null); // For full-page print

    // Thermal Print handler
    const handlePrintThermal = useReactToPrint({
        content: () => componentRef.current,
    });

    // Full-Page Print handler
    const handlePrintFullPage = useReactToPrint({
        content: () => componentRefFullPage.current,
    });

    const handlePayment = async () => {
        let get_api
        isAdmin ?
            get_api = await getMasterDataToken(
                getpaymentIdMaster + `?payment_id=${param1}`

            ) :
            get_api = await getClientUrlDataToken(
                authState.apiUrl,
                authState.userRole === 1 ? getpaymentId + `?payment_id=${param1}` : getpaymentIdRole + `?payment_id=${param1}`

            );
        if (get_api?.status === true) {
            setapidata(get_api?.payment);
            const invoices_map = Object.entries(
                get_api?.payment?.invoices_reflected || {}
            ).map(([id, invoice]) => ({
                id,
                invoice,
            })); setinvoice(invoices_map);
        } else if (get_api?.status >= 400 && get_api.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (get_api?.status >= 500 && get_api.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
        setspinnerTrans(false);
    };

    const redirectToInvoiceAdmin = async (data) => {
        let response = await getMasterDataToken(getShareApi + `?order_id=${data.order_id}`);
        if (response.status === true) {
            const toReciept = `${process.env.PUBLIC_URL}/invoice?order_id=${response.data}`;
            navigate(toReciept);
        }
    };

    return (
        <Fragment>
            {spinnerTrans && <Transparentspinner />}
            <style>
                {`
                    @media print {
                        @page {
                            size: A4;
                            margin: 0;
                        }
                        body {
                            margin: 0;
                            padding: 0;
                        }

                        /* Thermal Print */
                        .thermal-print {
                            width: 290px;
                            margin: 0;
                             position: absolute;
                              top: 0;
                              left: 0;
                               padding: 10px;
                            text-align: left;
                           
                        }
                        .thermal-print hr {
                            margin-top: -4px !important;
                        }

                        /* Full-page Print */
                        .full-page-print {
                            width: 100%;
                            padding: 20px;
                            text-align: left;
                        }
                        .full-page-print hr {
                            margin-top: 10px !important;
                        }

                        .detail-item {
                            display: flex;
                            justify-content: space-between;
                        }
                        .detail-item span {
                            text-align: left;
                        }
                    }
                `}
            </style>

            <div className="print-container" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', marginTop: '10px' }}>
                <div className="" style={{ backgroundColor: 'white', padding: '12px', borderRadius: '8px', maxWidth: '450px',minWidth:'300px' }}>

                    {/* Thermal Print Section */}
                    <div className="receipts thermal-print " style={{ textAlign: 'left' }} ref={componentRef}>
                        <hr className="hr-line" />
                        <div style={{ textAlign: 'center' }}>
                            {
                                isAdmin ?
                                    <>
                                        <img style={{ width: '150px', marginBottom: '2px' }} src={logo} alt='logo' />
                                        <h3>+91 7012733393</h3>
                                    </>
                                    :
                                    <>
                                        <h2>{apidata.company_name}</h2>
                                        <h3>+{apidata.company_country_code + " " + apidata.company_mobile}</h3>
                                    </>
                            }
                            <hr className="hr-line" style={{ marginTop: '5px' }} />
                            <h4>PAYMENT RECEIPT</h4>
                            <hr className="hr-line" style={{ marginTop: '5px' }} />
                        </div>
                        <h6>Customer Details:</h6>
                        {
                            isAdmin
                                ? <div className="customer-add">
                                    <p className="customer-name">{apidata?.company_name}</p>
                                    <p className="customer-ame">{apidata?.user_name}</p>
                                    <div className="customer-address"
                                        style={{
                                            wordWrap: 'break-word',
                                            overflowWrap: 'break-word',
                                            whiteSpace: 'normal',
                                        }}
                                    >
                                        <p>{apidata?.user_address}</p>
                                        <p className="customer-ame">{apidata?.user_mobile}</p>
                                    </div>
                                </div> :
                                <div className="customer-add">
                                    <p className="customer-name">{apidata.customer_name}</p>
                                    <div className="customer-address"
                                        style={{
                                            wordWrap: 'break-word',
                                            overflowWrap: 'break-word',
                                            whiteSpace: 'normal',
                                        }}
                                    >
                                        <p>{apidata.customer_address}</p>
                                    </div>
                                </div>
                        }

                        <hr className="hr-line" style={{ marginTop: '10px' }} />
                        <div className="details-container">
                            {!isAdmin &&

                                <div className="detail-item">
                                    <p className="left">Subscriber id# </p>
                                    {authState.userRole === 1 || authState.permissions.includes('show-customer-profile') ? (
                                        <Link to={`${process.env.PUBLIC_URL}/customers/customer/userProfile?id=${apidata.customer_id}`}>
                                            <span className="right text-decoration-underline">{apidata.subscriber_id}</span>
                                        </Link>
                                    ) : (
                                        apidata.subscriber_id
                                    )}
                                </div>
                            }
                            <div className="detail-item">
                                <p className="left">Receipt No# </p><span className="right">{apidata.receipt_no}</span>
                            </div>
                            <div className="detail-item">
                                <p className="left">Txn id# </p><span className="right">{apidata.payment}</span>
                            </div>
                            <div className="detail-item">
                                <p className="left">Transaction Date: </p><span className="right">{isAdmin ? apidata.paid_at : apidata.transaction_date}</span>
                            </div>
                            <div className="detail-item">
                                <p className="left">Payment Method: </p><span className="right">{apidata.payment_method_name}</span>
                            </div>
                            {
                                !isAdmin &&
                                <div className="detail-item">
                                    <p className="left">Sales agent: </p><span className="right">{apidata.sales_agent}</span>
                                </div>
                            }
                        </div>
                        <hr className="hr-line" style={{ marginTop: '-1px' }} />
                        <div className="paid-amount">
                            <p className="left">Paid Amount: </p><span className="right">{isAdmin ? '₹' : authState.currency} {apidata.paid_amount}</span>
                        </div>
                        <hr className="hr-line" style={{ marginTop: '-5px' }} />
                        <div className="invoice-details">
                            <div className="detail-item">
                                <p className="left" style={{ whiteSpace: 'nowrap' }}>Invoices reflected: </p>

                                {
                                    isAdmin ?

                                        <div style={{ cursor: 'pointer',color:'#534686',textDecoration:'underline' }} className='mt-1' onClick={() => redirectToInvoiceAdmin(apidata)}>

                                            {apidata?.invoice_number}
                                        </div>
                                        :
                                        invoice?.map((item) => (
                                            <div className="right d-flex mb-4 flex-wrap gap-1 align-items-end justify-content-end">
                                                <Link className='mt-2' to={`${process.env.PUBLIC_URL}/customers/customer/userProfile/invoice?invoice_id=${item.id}&customer_id=${apidata.customer_id}`}>
                                                    <span className="right ">

                                                        {item.invoice}
                                                    </span>
                                                </Link>
                                            </div>
                                        ))

                                }

                            </div>
                            {apidata.description != null && (
                                <div className="detail-item mt-4">
                                    <p className="left">Description:</p><span className="right">{apidata.description}</span>
                                </div>
                            )}
                            {apidata.reference !== null && (
                                <div className="detail-item">
                                    <p className="left">Ref:</p><span className="right mt-1">{apidata.reference}</span>
                                </div>
                            )}
                            {
                                !isAdmin &&
                                <>
                                    <div className="detail-item">
                                        <p className="left">Total Dues:</p><span className="right">{authState.currency} {apidata.total_dues}</span>
                                    </div>
                                    <div className="detail-item">
                                        <p className="left">Wallet Money</p><span className="right">{authState.currency} {apidata.wallet_money}</span>
                                    </div>
                                </>
                            }

                        </div>
                        {(!isAdmin) &&
                            apidata.next_payment_date !== '' && (
                                <div className="hypen mt-2">
                                    <p className="thank-you">Your next Due/Billing date is on {apidata.next_payment_date}</p>
                                </div>
                            )}
                        <p className='text-center'>Thank you</p>
                        <p className="hyphen" style={{ textAlign: 'center' }}>*******</p>
                    </div>

                    {/* Full Page Print Section */}
                    <div className='' style={{ display: 'none' }}>
                        <div className="receipts full-page-print" ref={componentRefFullPage}>
                            <div style={{ textAlign: 'center' }}>
                                <Row className="d-flex justify-content-between align-items-stretch">
                                    {
                                        isAdmin ?

                                            <Col sm="2" className="custom-col text-center">
                                                <Media className="h-100">
                                                    <div className="d-flex-center">
                                                        <Image
                                                            attrImage={{
                                                                className: 'd-flex-object img-60',
                                                                src: logo2,
                                                                alt: ''
                                                            }}
                                                            style={{ width: '100%', height: 'auto' }}
                                                        />

                                                    </div>
                                                </Media>
                                            </Col> :
                                            <Col sm="2" className="custom-col text-center">
                                                <Media className="h-100">
                                                    <div className="d-flex-center">
                                                        <Image
                                                            attrImage={{
                                                                className: 'd-flex-object img-60',
                                                                src: imageUrl,
                                                                alt: ''
                                                            }}
                                                            style={{ width: '100%', height: 'auto' }}
                                                        />
                                                    </div>
                                                </Media>
                                            </Col>
                                    }

                                    {
                                        isAdmin ?
                                            <Col sm="5" className="custom-col text-start">
                                                <Media className="flex-grow-1">
                                                    <div>
                                                        <H2
                                                            attrH2={{
                                                                className: 'media-heading text-left f-w-600 company-name',
                                                                style: { fontSize: '18px' }
                                                            }}
                                                        >
                                                            BillerQ
                                                        </H2>

                                                        <P>
                                                            <span className="digits">2nd Floor , KSUM, UL Cyberpark Nellikode PO, Kerala 673016</span><br />
                                                            info@billerQ.com
                                                            <br />
                                                            <span className="digits">+91 70127 33393
                                                            </span>
                                                        </P>
                                                    </div>
                                                </Media>
                                            </Col>
                                            : <Col sm="5" className="custom-col text-start">
                                                <Media className="flex-grow-1">
                                                    <div>
                                                        <H2
                                                            attrH2={{
                                                                className: 'media-heading text-left f-w-600 company-name',
                                                                style: { fontSize: '18px' }
                                                            }}
                                                        >
                                                            {apidata.company_name}
                                                        </H2>

                                                        <P>
                                                            <span className="digits">{apidata.company_address}</span><br />
                                                            {apidata.company_email}
                                                            <br />
                                                            <span className="digits">+{`${apidata.company_country_code}${apidata.company_mobile}`}</span>
                                                        </P>
                                                    </div>
                                                </Media>
                                            </Col>


                                    }



                                    {
                                        isAdmin ?
                                            <Col sm="5" className="custom-col text-end">
                                                <div className="text-end">
                                                    <h5>
                                                        <span className="digits counter">Bill To: </span>
                                                    </h5>
                                                    <P>
                                                        <strong>{apidata.company_name}</strong> <br />
                                                        {apidata.user_name} <br />
                                                        {apidata.user_address}<br />
                                                        {Mob} : + {apidata.user_mobile}<br />
                                                        {Email} : {apidata.email}<br />
                                                        {TaxIn} : {apidata.transaction_id}<br />
                                                    </P>
                                                </div>
                                            </Col>
                                            :
                                            <Col sm="5" className="custom-col text-end">
                                                <div className="text-end">
                                                    <h5>
                                                        <span className="digits counter">Bill To: </span>
                                                    </h5>
                                                    <P>
                                                        <strong>{apidata.customer_name}</strong> <br />
                                                        {apidata.customer_address}<br />
                                                        {Mob} : + {apidata.customer_number}<br />
                                                        {Email} : {apidata.customer_email}<br />
                                                        {TaxIn} : {apidata.transaction_id}<br />
                                                    </P>
                                                </div>
                                            </Col>
                                    }
                                </Row>


                                <hr className="hr-line" style={{ marginTop: '5px' }} />
                                <h4>PAYMENT RECEIPT</h4>
                                <hr className="hr-line" style={{ marginTop: '5px' }} />
                            </div>
                            <div className="details-container">
                                {
                                    !isAdmin &&
                                    <div className="detail-item">
                                        <p className="left">Subscriber id# </p>
                                        {authState.userRole === 1 || authState.permissions.includes('show-customer-profile') ? (
                                            <Link to={`${process.env.PUBLIC_URL}/customers/customer/userProfile?id=${apidata.customer_id}`}>
                                                <span className="right text-decoration-underline">{apidata.subscriber_id}</span>
                                            </Link>
                                        ) : (
                                            apidata.subscriber_id
                                        )}
                                    </div>
                                }
                                <div className="detail-item">
                                    <p className="left">Receipt No# </p><span className="right">{apidata.receipt_no}</span>
                                </div>
                                <div className="detail-item">
                                    <p className="left">Txn id# </p><span className="right">{apidata.payment}</span>
                                </div>
                                <div className="detail-item">
                                    <p className="left">Transaction Date: </p><span className="right">{
                                        isAdmin ? apidata.paid_at : apidata.transaction_date}</span>
                                </div>
                                <div className="detail-item">
                                    <p className="left">Payment Method: </p><span className="right">{apidata.payment_method_name}</span>
                                </div>
                                {
                                    !isAdmin &&
                                    <div className="detail-item">
                                        <p className="left">Sales agent: </p><span className="right">{apidata.sales_agent}</span>
                                    </div>
                                }
                            </div>
                            <hr className="hr-line" style={{ marginTop: '-1px' }} />
                            <div className="paid-amount">
                                <p className="left">Paid Amount: </p><span className="right">{authState.currency} {apidata.paid_amount}</span>
                            </div>
                            <hr className="hr-line" style={{ marginTop: '-5px' }} />
                            <div className="invoice-details">
                                <div className="detail-item">
                                    <p className="left" style={{ whiteSpace: 'nowrap' }}>Invoices reflected: </p><div className="right d-flex flex-wrap gap-1 align-items-end justify-content-end">
                                        {
                                            isAdmin ?
                                                <div className="right  mb-4">
                                                    <Link className='' to={`${process.env.PUBLIC_URL}/customers/customer/userProfile/invoice?invoice_id=${apidata?.invoice_number}&customer_id=${apidata.customer_id}`}>
                                                        <span className="rigt ">

                                                            {apidata?.invoice_number}
                                                        </span>
                                                    </Link>
                                                </div>
                                                :
                                                invoice?.map((item) => (
                                                    <div className="right d-flex flex-wrap gap-1 mb-4 align-items-end justify-content-end">
                                                        <Link className='mt-2' to={`${process.env.PUBLIC_URL}/customers/customer/userProfile/invoice?invoice_id=${item.id}&customer_id=${apidata.customer_id}`}>
                                                            <span className="right ">

                                                                {item.invoice}
                                                            </span>
                                                        </Link>
                                                    </div>
                                                ))

                                        }

                                    </div>
                                </div>
                                {apidata.description != null && (
                                    <div className="detail-item mt-4">
                                        <p className="left">Description:</p><span className="right">{apidata.description}</span>
                                    </div>
                                )}
                                {apidata.reference !== null && (
                                    <div className="detail-item">
                                        <p className="left">Ref:</p><span className="right">{apidata.reference}</span>
                                    </div>
                                )}
                                {
                                    !isAdmin &&
                                    <>
                                        <div className="detail-item">
                                            <p className="left">Total Dues:</p><span className="right">{authState.currency} {apidata.total_dues}</span>
                                        </div>
                                        <div className="detail-item">
                                            <p className="left">Wallet Money</p><span className="right">{authState.currency} {apidata.wallet_money}</span>
                                        </div>
                                    </>
                                }
                            </div>
                            {!isAdmin &&
                                apidata.next_payment_date !== '' && (
                                    <div className="hypen mt-2">
                                        <p className="thank-you">Your next Due/Billing date is on {apidata.next_payment_date}</p>
                                    </div>
                                )}
                            <p className='text-center mt-5'>Thank you</p>
                            <p className="hyphen" style={{ textAlign: 'center' }}>*******</p>
                        </div>

                    </div>
                    <hr className="hr-line" style={{ marginTop: '-5px' }} />
                    <div className="button-print text-center">
                        <button className="print-button" onClick={handlePrintThermal}>Thermal Print</button>
                        <button className="print-button" onClick={handlePrintFullPage}>Print</button>

                    </div>
                </div>
            </div>
        </Fragment>
    );
};

export default RenewSub;
